        }

        hasLiked = (likeResult.count || 0) > 0;
        hasBookmarked = (bookmarkResult.count || 0) > 0;
    }

    return {
        ...journal,
        has_liked: hasLiked,
        has_bookmarked: hasBookmarked
    };
}

