        .from('journals')
        .select(`
            *,
            users(*),
            like_count: likes(count),
            comment_count: comments(count),
            bookmark_count: bookmarks(count),
            repost_source:journals!repost_source_journal_id(
                id, title, content, post_type, canvas_doc, created_at,
                users(id, name, image_url, badge)
            )
        `)
        .eq('id', journalId)
        .eq('privacy', 'public')
        .maybeSingle();

    if (journalError) {
        console.error('supabase error while fetching journal by id:', journalError.message);
        throw { status: 500, error: 'supabase error while fetching journal by id' };
    }

    if (!journal) {
        return null;
    }

    let hasLiked = false;
    let hasBookmarked = false;

    if (userId) {
        const [likeResult, bookmarkResult] = await Promise.all([
            supabase
                .from('likes')
                .select('journal_id', { count: 'exact', head: true })
                .eq('journal_id', journalId)
                .eq('user_id', userId),
            supabase
                .from('bookmarks')
                .select('journal_id', { count: 'exact', head: true })
                .eq('journal_id', journalId)
