163→        return () =>{
164→            document.removeEventListener('click', handleClickOutside)
165→        }
166→    }, [])
167→
168→     useEffect(() =>{
169→         console.log(data)
170→    }, [data])
171→
172→    const handleClickSettings = (e, notifId) =>{
173→        e.stopPropagation();
174→        // console.log(notifId)
175→        setSettingsId(settingsId === notifId ? null : notifId);
176→    }
177→
178→    const mutationRespondConstellation = useRespondConstellationMutation(session);
179→    const mutationDeleteNotif  = useUserDeleteNotificationMutation(session);
180→
181→    const handleClickDeleteNotification = async(e, notifId, source) =>{
182→        e.stopPropagation();
183→        try {
184→           const message = mutationDeleteNotif.mutateAsync({notifId, source});
185→            if(message){
186→                // console.log(message)
187→            }
188→        } catch (error) {
189→            console.error('error while deleting notification:', error)
190→        }
191→    }
192→
193→    if(notifications.length === 0 && !isLoading){
194→        return(
195→            <div className='notification-loading-container'>
196→                No notifications availabe
197→            </div>
198→        )
