203→            <div className="notification-loading-container">
204→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
205→            </div>
206→        )
207→    }
208→
209→    return(
210→        <>
211→        <div ref={scrollToTop}/>
212→        <div className="notifications-container">
213→            {notifications?.map((notification) => {
214→                const isOpinion = notification?.source === 'opinion';
215→                const displayType = isOpinion ? 'opinion_reply' : notification?.type;
216→                const parsedContent = !isOpinion ? ParseContent(notification?.journals?.content) : null;
217→
218→                return(
219→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
220→
221→                    <div className="notification-cards-child-container">
222→
223→                        <div className="notification-icon-container">
224→                            {iconArray.map((icon, index) => (
225→                                <div className="notification-icon" key={index}>
226→                                    {icon.type === displayType ? icon.icon : null}
227→                                </div>
228→                            ))}
229→                        </div>
230→
231→                        <div className="notification-contents-container">
232→
233→                            <div className="notification-sender-user-metadata">
234→                                <div className="notification-sender-user-metadata-child">
235→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
236→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
237→                                    </div>
238→
239→                                    <div className="notif-sender-name-container">
240→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
241→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
242→                                        <p className="notif-type">{FormatNotificationType(displayType)}</p>
243→                                    </div>
244→
