247→                                    </div>
248→                                </div>
249→                                <div className="notification-settings">
250→                                    {settingsId === notification.id && (
251→                                        <AnimatePresence>
252→                                        <motion.div
253→                                        initial={{opacity: 0, scale: 0}}
254→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
255→                                        exit={{ opacity: 0, scale: 0,
256→                                            transition: {
