 27→const normalizeInteractionFlag = (value) => {
 28→    if(typeof value === 'boolean') return value;
 29→    if(typeof value === 'string'){
 30→        const normalized = value.trim().toLowerCase();
 31→        if(normalized === 'true') return true;
 32→        if(normalized === 'false') return false;
 33→    }
 34→    if(typeof value === 'number'){
 35→        return value === 1;
 36→    }
 37→    return Boolean(value);
 38→};
 39→
 40→const normalizeCount = (value) => {
 41→    const number = Number(value);
 42→    if(!Number.isFinite(number) || number < 0){
 43→        return 0;
 44→    }
 45→    return number;
 46→};
 47→
 48→const getNextToggleCount = (isActive, currentCount) => {
 49→    return isActive
 50→        ? Math.max(0, currentCount - 1)
 51→        : currentCount + 1;
 52→};
