206→        }
207→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
208→        bookmarkInFlightRef.current = true;
209→        setIsBookmarked(!wasBookmarked);
210→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
211→        let response = null;
212→        try {
213→            response = await mutationBookmark.mutateAsync({ journalId });
214→        } finally {
215→            bookmarkInFlightRef.current = false;
216→        }
217→        
218→        if(timeOutRefBookmark.current){
219→            clearTimeout(timeOutRefBookmark.current);
220→        }
221→        if (response?.message === 'success') {
222→            setBookmarkedMessage('Post was added to your Bookmarks'); 
223→        } else if(response?.message === 'deleted'){
224→            setBookmarkedMessage('Post was removed from your Bookmarks');
225→        }
226→            
227→        timeOutRefBookmark.current = setTimeout(() => {
228→            setBookmarkedMessage('');
229→        }, 1500);
230→
231→    }
232→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
233→
234→    const mutationFollow = useFollowMutation(session);
235→    const handleClickFollow = async (e, followingId, followerId) => {
236→        e.stopPropagation();
237→        mutationFollow.mutate({ followingId, followerId });
238→    }
239→    const debounceClickFollow = debounce(handleClickFollow, 100);
240→
241→    const handleBackLocation = (e) => {
242→        e.stopPropagation();
243→        window.history.back();
244→    }
245→
246→    const hanldeClickComments = (e) => {
247→        e.stopPropagation();
248→        setShowCommentsContainer(true);
249→    }
250→
251→    const handleRemixCanvas = (e) => {
252→        e.stopPropagation();
253→        if(!session){
254→            return;
255→        }
256→
257→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
258→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
259→            ? sourceTitle
260→            : `Remix: ${sourceTitle || 'Canvas'}`;
261→
262→        navigate('/home', {
263→            state: {
264→                openEditor: true,
265→                editorMode: 'canvas',
266→                initialTitle: remixTitle,
267→                initialCanvasDoc: postData?.canvasDoc || null,
268→                remixSource: {
269→                    journalId: postData?.journalId,
270→                    authorName: postData?.name || 'Unknown'
271→                }
272→            }
273→        });
274→    }
275→
276→    const handleCLoseComments = () => {
277→        setShowCommentsContainer(false);
278→    }
279→
280→    useEffect(() => {
281→        if (!postData) return;
282→        setLikesCount(normalizeCount(postData?.likesCount));
283→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
284→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
285→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
286→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked]);
287→
288→    useEffect(() => {
289→        if (postData?.title) {
290→            document.title = `${postData.title} | Iskrib`;
291→            return () => {
292→                document.title = 'Iskrib';
293→            };
294→        }
295→
296→        document.title = 'Iskrib';
297→    }, [postData?.title]);
298→
299→    useEffect(() => {
300→        const hideBackBttn = () => {
301→            setShowBackButton(false);
302→            if (timeOutRef.current) {
303→                clearTimeout(timeOutRef.current);
304→            }
305→            timeOutRef.current = setTimeout(() => {
306→                setShowBackButton(true);
307→            }, 300);
308→        }
309→
