/* ── Content Viewer — Notion-inspired redesign ── */

/* ── Loading ── */
.cv-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100vh;
    background-color: var(--bg-primary);
}

/* ── Container ── */
.cv-container {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
    min-height: 100vh;
    background-color: var(--bg-primary);
    overflow-y: auto;
}
.cv-container::-webkit-scrollbar {
    display: none;
    width: 0;
    height: 0;
}

/* ── Back header ── */
.cv-header {
    position: fixed;
    top: 0;
    display: flex;
    align-items: center;
    gap: 10px;
    width: 100%;
    max-width: 720px;
    height: 44px;
    padding: 0 16px;
    box-sizing: border-box;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-light);
    z-index: 10;
    user-select: none;
}
.cv-back-btn {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 28px;
    height: 28px;
    border-radius: 4px;
    background: transparent;
    border: none;
    cursor: pointer;
    padding: 0;
    transition: background 0.1s ease;
}
.cv-back-btn:hover {
    background: var(--bg-hover);
}
.cv-back-btn svg {
    width: 18px;
    height: 18px;
    fill: var(--text-secondary);
}
.cv-header-label {
    font-family: var(--font-ui);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-secondary);
    margin: 0;
    padding: 0;
}

/* ── Article wrapper ── */
.cv-article {
    max-width: 620px;
    width: 100%;
    padding: 0 24px;
    box-sizing: border-box;
}

/* ── Title ── */
.cv-title {
    margin: 80px 0 0 0;
    padding: 0;
    font-family: var(--font-serif);
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--text-heading);
    line-height: 1.2;
    letter-spacing: -0.01em;
}

/* ── Metadata ── */
.cv-meta {
    display: flex;
    align-items: flex-start;
