/* ── Content Viewer — Notion-inspired redesign ── */

/* ── Loading ── */
.cv-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100vh;
    background-color: var(--bg-primary);
}

/* ── Container ── */
.cv-container {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
    min-height: 100vh;
    background-color: var(--bg-primary);
    overflow-y: auto;
}
.cv-container::-webkit-scrollbar {
    display: none;
    width: 0;
    height: 0;
}

/* ── Back header ── */
.cv-header {
    position: fixed;
    top: 0;
    display: flex;
    align-items: center;
    gap: 10px;
    width: 100%;
    max-width: 720px;
    height: 44px;
    padding: 0 16px;
    box-sizing: border-box;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-light);
    z-index: 10;
    user-select: none;
}
.cv-back-btn {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 28px;
    height: 28px;
    border-radius: 4px;
    background: transparent;
    border: none;
    cursor: pointer;
    padding: 0;
    transition: background 0.1s ease;
}
.cv-back-btn:hover {
    background: var(--bg-hover);
}
.cv-back-btn svg {
    width: 18px;
    height: 18px;
    fill: var(--text-secondary);
}
.cv-header-label {
    font-family: var(--font-ui);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-secondary);
    margin: 0;
    padding: 0;
}

/* ── Article wrapper ── */
.cv-article {
    max-width: 620px;
    width: 100%;
    padding: 0 24px;
    box-sizing: border-box;
}

/* ── Title ── */
.cv-title {
    margin: 80px 0 0 0;
    padding: 0;
    font-family: var(--font-serif);
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--text-heading);
    line-height: 1.2;
    letter-spacing: -0.01em;
}

/* ── Metadata ── */
.cv-meta {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    margin-top: 24px;
    padding: 0;
}
.cv-avatar-wrap {
    flex-shrink: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    border-radius: 50%;
    cursor: pointer;
}
.cv-avatar-wrap.cv-avatar-ring-legend {
    border: 2px solid #FFD700;
    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
}
.cv-avatar-wrap.cv-avatar-ring-og {
    border: 2px solid #9B59FF;
    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
}
.cv-avatar {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    object-fit: cover;
}
.cv-meta-info {
    display: flex;
    flex-direction: column;
    gap: 2px;
    min-width: 0;
}
.cv-meta-top {
    display: flex;
    align-items: center;
    gap: 6px;
    flex-wrap: wrap;
}
.cv-author-name {
    font-family: var(--font-ui);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-secondary);
    cursor: pointer;
    transition: color 0.1s ease;
    margin: 0;
    padding: 0;
}
.cv-author-name:hover {
    color: var(--text-primary);
}
.cv-follow-btn {
    font-family: var(--font-ui);
    font-size: 0.8125rem;
    font-weight: 500;
    color: var(--accent-purple);
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    user-select: none;
    transition: text-decoration 0.1s ease;
}
.cv-follow-btn:hover {
    text-decoration: underline;
}
.cv-follow-btn--following {
    color: var(--text-muted);
}
.cv-follow-btn--following:hover {
    color: rgb(220, 80, 80);
    text-decoration: none;
}
.cv-meta-bottom {
    display: flex;
    align-items: center;
    gap: 6px;
}
.cv-date,
.cv-read-time {
    font-family: var(--font-ui);
    font-size: 0.8125rem;
    font-weight: 400;
    color: var(--text-muted);
    margin: 0;
    padding: 0;
}
.cv-meta-dot {
    font-size: 0.8125rem;
    color: var(--text-muted);
}

/* ── Action bar ── */
.cv-actions {
    display: flex;
    align-items: center;
    gap: 4px;
    margin-top: 20px;
    padding: 8px 0;
    border-top: 1px solid var(--border-light);
}
.cv-action-btn {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 4px 8px;
    border-radius: 4px;
    border: none;
    background: transparent;
    cursor: pointer;
    transition: background 0.1s ease;
    font-family: var(--font-ui);
    font-size: 0.8125rem;
    font-weight: 400;
    color: var(--text-muted);
}
.cv-action-btn:hover {
    background: var(--bg-hover);
}
.cv-action-btn svg {
    width: 18px;
    height: 18px;
    flex-shrink: 0;
}
.cv-action-btn--end {
    margin-left: auto;
}

/* ── Body content (Lexical) ── */
.cv-body {
    margin-top: 32px;
    margin-bottom: 80px;
    font-family: var(--font-serif);
    font-size: 1.125rem;
    font-weight: 400;
    color: var(--text-primary);
    line-height: 1.8;
    letter-spacing: -0.003em;
}
.cv-body .editor-paragraph {
    margin: 0 0 0.75rem;
}
.cv-body .editor-heading-h1 {
    font-size: 1.75rem;
