.cv-remix-btn{
    border: 1px solid color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
    background: var(--bg-secondary);
    color: var(--accent-purple);
    border-radius: 999px;
    padding: 0.4rem 0.82rem;
    font-size: 0.75rem;
    font-weight: 640;
    cursor: pointer;
