    font-family: var(--font-ui);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-secondary);
    margin: 0;
    padding: 0;
}

/* ── Article wrapper ── */
.cv-article {
    max-width: 620px;
    width: 100%;
    padding: 0 24px;
    box-sizing: border-box;
}

/* ── Title ── */
.cv-title {
    margin: 80px 0 0 0;
    padding: 0;
    font-family: var(--font-serif);
    font-size: 2.5rem;
    font-weight: 700;
    color: var(--text-heading);
    line-height: 1.2;
    letter-spacing: -0.01em;
}

/* ── Metadata ── */
.cv-meta {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    margin-top: 24px;
    padding: 0;
}
.cv-avatar-wrap {
    flex-shrink: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    border-radius: 50%;
    cursor: pointer;
}
.cv-avatar-wrap.cv-avatar-ring-legend {
    border: 2px solid #FFD700;
    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
}
.cv-avatar-wrap.cv-avatar-ring-og {
    border: 2px solid #9B59FF;
    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
}
.cv-avatar {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    object-fit: cover;
}
.cv-meta-info {
    display: flex;
    flex-direction: column;
    gap: 2px;
    min-width: 0;
}
.cv-meta-top {
    display: flex;
    align-items: center;
    gap: 6px;
    flex-wrap: wrap;
}
.cv-author-name {
    font-family: var(--font-ui);
    font-size: 0.875rem;
    font-weight: 500;
    color: var(--text-secondary);
    cursor: pointer;
    transition: color 0.1s ease;
    margin: 0;
    padding: 0;
}
.cv-author-name:hover {
    color: var(--text-primary);
}
.cv-follow-btn {
    font-family: var(--font-ui);
