  5→const normalizeUrl = (url = "") => {
  6→    if(typeof url !== "string" || !url){
  7→        return "";
  8→    }
  9→
 10→    try {
 11→        const parsed = new URL(url);
 12→        return `${parsed.origin}${parsed.pathname}`;
 13→    } catch {
 14→        return "";
 15→    }
 16→};
 17→
 18→const extractBackgroundImageUrl = (background) => {
 19→    if(!background || typeof background !== "object"){
 20→        return "";
 21→    }
 22→
 23→    const rawBackgroundImage = background?.backgroundImage;
 24→    if(typeof rawBackgroundImage !== "string"){
 25→        return "";
 26→    }
 27→
 28→    const match = rawBackgroundImage.match(/url\(['"]?(.*?)['"]?\)/i);
 29→    const extractedUrl = match?.[1] || rawBackgroundImage;
 30→    return normalizeUrl(extractedUrl);
 31→};
 32→
 33→const doesUrlMatchDeletedPath = (candidateUrl, bucket, path, deletedPublicUrl = "", providedUrl = "") => {
 34→    const normalizedCandidateUrl = normalizeUrl(candidateUrl);
 35→    if(!normalizedCandidateUrl){
 36→        return false;
 37→    }
 38→
 39→    const normalizedDeletedPublicUrl = normalizeUrl(deletedPublicUrl);
 40→    const normalizedProvidedUrl = normalizeUrl(providedUrl);
 41→
 42→    if(normalizedDeletedPublicUrl && normalizedCandidateUrl === normalizedDeletedPublicUrl){
 43→        return true;
 44→    }
 45→
 46→    if(normalizedProvidedUrl && normalizedCandidateUrl === normalizedProvidedUrl){
 47→        return true;
 48→    }
 49→
 50→    return normalizedCandidateUrl.endsWith(`/${bucket}/${path}`);
 51→};
