 76→export const deleteProfileMediaImageService = async(userId, bucket, path, url = "") => {
 77→    if(!userId){
 78→        console.error("userId is undefined");
 79→        throw {status: 400, error: "userId is undefined"};
 80→    }
 81→
 82→    if(!bucket || typeof bucket !== "string"){
 83→        console.error("bucket is undefined");
 84→        throw {status: 400, error: "bucket is undefined"};
 85→    }
 86→
 87→    if(!ALLOWED_MEDIA_BUCKETS.has(bucket)){
 88→        console.error("bucket is not allowed");
 89→        throw {status: 400, error: "bucket is not allowed"};
 90→    }
 91→
 92→    if(!path || typeof path !== "string"){
 93→        console.error("path is undefined");
 94→        throw {status: 400, error: "path is undefined"};
 95→    }
 96→
 97→    const normalizedPath = path.trim();
 98→    const expectedPrefix = `user_id_${userId}/`;
 99→    if(!normalizedPath.startsWith(expectedPrefix)){
100→        console.error("forbidden media path for user");
101→        throw {status: 403, error: "forbidden media path"};
102→    }
103→
104→    const {error: removeError} = await supabase.storage
105→        .from(bucket)
106→        .remove([normalizedPath]);
107→
108→    if(removeError){
109→        console.error("supabase error while deleting profile media image:", removeError.message);
110→        throw {status: 500, error: "supabase error while deleting profile media image"};
111→    }
112→
113→    let clearedAvatar = false;
114→    let clearedBackground = false;
115→
116→    if(bucket === "avatars" || bucket === "background"){
117→        const {data: userData, error: userDataError} = await supabase
118→            .from("users")
119→            .select("id, image_url, background")
120→            .eq("id", userId)
121→            .maybeSingle();
122→
123→        if(userDataError){
124→            console.error("supabase error while loading user profile for media cleanup:", userDataError.message);
125→            throw {status: 500, error: "supabase error while loading user profile for media cleanup"};
126→        }
127→
128→        if(userData){
129→            const {data: publicUrlData} = supabase.storage
130→                .from(bucket)
131→                .getPublicUrl(normalizedPath);
132→
133→            const deletedPublicUrl = publicUrlData?.publicUrl || "";
134→            const updates = {};
135→
136→            if(bucket === "avatars"){
137→                const matchesAvatar = doesUrlMatchDeletedPath(userData?.image_url, bucket, normalizedPath, deletedPublicUrl, url);
138→                if(matchesAvatar){
139→                    updates.image_url = null;
140→                    clearedAvatar = true;
141→                }
142→            }
143→
144→            if(bucket === "background"){
145→                const backgroundImageUrl = extractBackgroundImageUrl(userData?.background);
146→                const matchesBackground = doesUrlMatchDeletedPath(backgroundImageUrl, bucket, normalizedPath, deletedPublicUrl, url);
147→                if(matchesBackground){
148→                    updates.background = null;
149→                    clearedBackground = true;
150→                }
151→            }
152→
153→            if(Object.keys(updates).length > 0){
154→                const {error: updateProfileError} = await supabase
155→                    .from("users")
156→                    .update(updates)
157→                    .eq("id", userId);
158→
159→                if(updateProfileError){
160→                    console.error("supabase error while clearing profile media references:", updateProfileError.message);
161→                    throw {status: 500, error: "supabase error while clearing profile media references"};
162→                }
163→            }
164→        }
165→    }
166→
167→    return {
168→        deleted: true,
169→        bucket: bucket,
170→        path: normalizedPath,
171→        clearedAvatar: clearedAvatar,
172→        clearedBackground: clearedBackground
173→    };
174→};
