413→const resolveMediaUrl = async(bucket, path) => {
414→    const {data: signedUrlData, error: signedUrlError} = await supabase.storage
415→        .from(bucket)
416→        .createSignedUrl(path, 60 * 60);
417→
418→    if(!signedUrlError && signedUrlData?.signedUrl){
419→        return signedUrlData.signedUrl;
420→    }
421→
422→    const {data: publicUrlData} = supabase.storage
423→        .from(bucket)
424→        .getPublicUrl(path);
425→
426→    return publicUrlData?.publicUrl || null;
427→};
