429→const listMediaChunkForBucket = async(bucket, userId, offset, limit) => {
430→    const folderPath = `user_id_${userId}`;
431→
432→    const {data: bucketItems, error: bucketError} = await supabase.storage
433→        .from(bucket)
434→        .list(folderPath, {
435→            limit: limit,
436→            offset: offset,
437→            sortBy: {column: 'name', order: 'desc'}
438→        });
439→
440→    if(bucketError){
441→        return {
442→            bucket: bucket,
443→            nextOffset: offset,
444→            exhausted: true,
445→            items: [],
446→            error: bucketError.message
447→        };
448→    }
449→
450→    const listedItems = Array.isArray(bucketItems) ? bucketItems : [];
451→    const normalizedItems = listedItems
452→        .filter((item) => item?.name && hasSupportedMediaExtension(item.name))
453→        .map((item) => {
454→            const path = `${folderPath}/${item.name}`;
455→            const createdAt = item.created_at || item.updated_at || null;
456→
457→            return {
458→                bucket: bucket,
459→                path: path,
460→                name: item.name,
461→                createdAt: createdAt,
462→                timestamp: parseMediaTimestamp(item)
463→            };
464→        });
465→
466→    return {
467→        bucket: bucket,
468→        nextOffset: offset + listedItems.length,
469→        exhausted: listedItems.length < limit,
470→        items: normalizedItems,
471→        error: null
472→    };
473→};
474→
475→const hydrateMediaItems = async(items) => {
476→    if(!Array.isArray(items) || items.length === 0){
477→        return [];
478→    }
479→
480→    const hydrated = await Promise.all(items.map(async(item) => {
481→        const url = await resolveMediaUrl(item.bucket, item.path);
482→        if(!url){
483→            return null;
484→        }
485→
486→        return {
487→            id: `${item.bucket}-${item.path}`,
488→            bucket: item.bucket,
489→            path: item.path,
490→            name: item.name,
491→            createdAt: item.createdAt || null,
492→            timestamp: item.timestamp || 0,
493→            url: url
494→        };
495→    }));
496→
497→    return hydrated.filter(Boolean);
498→};
