 298→const hasSupportedMediaExtension = (fileName = '') => {
 299→    const lowerFileName = fileName.toLowerCase();
 300→    return PROFILE_MEDIA_EXTENSIONS.some((ext) => lowerFileName.endsWith(ext));
 301→};
