 370→const parseCanvasGalleryCursor = (cursor, expectedSort = 'hottest') => {
 371→    const fallback = {
 372→        offset: 0,
 373→        sort: expectedSort
 374→    };
 375→
 376→    if(!cursor){
 377→        return fallback;
 378→    }
 379→
 380→    try {
 381→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 382→        const parsed = JSON.parse(decoded);
 383→        const parsedSort = typeof parsed?.sort === 'string' && parsed.sort.toLowerCase().trim() === 'newest'
 384→            ? 'newest'
 385→            : 'hottest';
 386→
 387→        if(parsedSort !== expectedSort){
 388→            return fallback;
 389→        }
 390→
 391→        const parsedOffset = Number(parsed?.offset);
 392→        const normalizedOffset = Number.isNaN(parsedOffset) || parsedOffset < 0
 393→            ? 0
 394→            : Math.floor(parsedOffset);
 395→
 396→        return {
 397→            offset: normalizedOffset,
 398→            sort: parsedSort
 399→        };
 400→    } catch {
 401→        return fallback;
 402→    }
 403→};
