 803→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
 804→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
 805→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
 806→    }
 807→
 808→    const parsedLimit = parseInt(limit);
 809→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
 810→    const isNewest = normalizedSort === 'newest';
 811→    const parsedCursor = parseCanvasGalleryCursor(cursor, isNewest ? 'newest' : 'hottest');
 812→    const cursorOffset = parsedCursor.offset;
 813→
 814→    const baseQuery = supabase
 815→        .from('journals')
 816→        .select(`
 817→            *,
 818→            users(*),
 819→            like_count: likes(count),
 820→            comment_count: comments(count),
 821→            bookmark_count: bookmarks(count)
 822→        `)
 823→        .eq('privacy', 'public')
 824→        .eq('post_type', 'canvas')
 825→        .order('created_at', {ascending: false})
 826→        .order('id', {ascending: false});
 827→
 828→    const {data: journals, error: journalsError} = isNewest
 829→        ? await baseQuery.range(cursorOffset, cursorOffset + parsedLimit)
 830→        : await baseQuery.limit(CANVAS_GALLERY_HOT_FETCH_LIMIT);
 831→
 832→    if(journalsError){
 833→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
 834→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
 835→    }
 836→
 837→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
 838→    const normalizedJournals = enrichedJournals.map((journal) => ({
 839→        ...journal,
 840→        hot_score: scoreJournalHotness(journal)
 841→    }));
 842→
 843→    if(!isNewest){
 844→        normalizedJournals.sort((a, b) => {
 845→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
 846→            if(scoreDiff !== 0){
 847→                return scoreDiff;
 848→            }
 849→
 850→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 851→            if(dateDiff !== 0){
 852→                return dateDiff;
 853→            }
 854→
 855→            return (b?.id || 0) - (a?.id || 0);
 856→        });
 857→    }
 858→
 859→    const paginatedJournals = isNewest
 860→        ? normalizedJournals
 861→        : normalizedJournals.slice(cursorOffset, cursorOffset + parsedLimit + 1);
 862→    const hasMore = paginatedJournals.length > parsedLimit;
 863→    const data = hasMore ? paginatedJournals.slice(0, parsedLimit) : paginatedJournals;
 864→    const nextCursor = hasMore
 865→        ? encodeCanvasGalleryCursor(cursorOffset + data.length, isNewest ? 'newest' : 'hottest')
 866→        : null;
 867→
 868→    return {
 869→        data: data,
 870→        sort: isNewest ? 'newest' : 'hottest',
 871→        totalCandidates: normalizedJournals.length,
 872→        hasMore: hasMore,
 873→        nextCursor: nextCursor
 874→    };
 875→}
