1262→    const {data: bookMarksData, error: errorBookmarks, count} = await query;
1263→
1264→    if(errorBookmarks){
1265→        console.error('supabase error:', errorBookmarks.message);
1266→        throw {status: 500, error: 'supabase error while fetching bookmarks'}
1267→    }
1268→
1269→    const journalIds = bookMarksData?.map((bookmark) => bookmark.journals.id);
1270→
1271→    if(journalIds.length === 0){
1272→        return {data: [], hasMore: false}
1273→    }
1274→
1275→    let hasLikedPromise;
1276→    let hasBookmarkedPromise;
1277→
1278→    if(journalIds){
1279→        hasLikedPromise = supabase
1280→        .from('likes')
1281→        .select('journal_id')
1282→        .in('journal_id', journalIds)
1283→        .eq('user_id', userId)
1284→
1285→        hasBookmarkedPromise = supabase
1286→        .from('bookmarks')
1287→        .select('journal_id')
1288→        .in('journal_id', journalIds)
1289→        .eq('user_id', userId)
1290→    }
1291→
1292→    const [hasLiked, hasBookMarked] = await Promise.all([
1293→        hasLikedPromise, hasBookmarkedPromise
1294→    ])
1295→
1296→    const {data: hasLikedResult, error: errorHasLikedResult} = hasLiked;
1297→    const {data: hasBookMarkedResult, error: errorHasbookmarkedResult} = hasBookMarked;
1298→
1299→    if(errorHasLikedResult || errorHasbookmarkedResult){
1300→        console.error('supabase error while fetching data:', errorHasLikedResult.message || errorHasbookmarkedResult.message);
1301→        throw {status: 500, error: 'supabase error while fetching data'};
1302→    }
1303→    
1304→    const userHasLikedSet = new Set(hasLikedResult.map((journal) => journal.journal_id) || []);
1305→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id) || []);
1306→
1307→    const hasMore = bookMarksData.length > paresedLimit;
1308→
1309→
1310→    const formattedData = bookMarksData.map((b) => ({
1311→        ...b,
1312→        has_liked: userHasLikedSet.has(b.journals.id),
1313→        has_bookmarked: userHasBookmarkedSet.has(b.journals.id),
1314→    }))
1315→
1316→    const slicedData = hasMore ? formattedData.splice(0, paresedLimit) : formattedData;
1317→
1318→    return {
1319→        bookmarks: slicedData,
1320→        hasMore: hasMore,
1321→        totalBookmarks: before ? null : count
1322→    }
1323→}
