1325→export const searchJournalsService = async(query, limit, userId) => {
1326→    const normalizedQuery = normalizeSearchQuery(query);
1327→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1328→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1329→    }
1330→
1331→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1332→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1333→    }
1334→
1335→    const parsedLimit = parseInt(limit);
1336→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1337→
1338→    const selectColumns = `
1339→        *,
1340→        users(*),
1341→        like_count: likes(count),
1342→        comment_count: comments(count),
1343→        bookmark_count: bookmarks(count)
1344→    `;
1345→
1346→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1347→    // fallback to keyword search so endpoint still returns useful data.
1348→    try {
1349→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1350→
1351→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1352→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1353→                query_embedding: queryEmbedding,
1354→                match_count: fetchLimit,
1355→                similarity_threshold: 0.35
1356→            });
1357→
1358→            if(matchError){
1359→                console.error('semantic search rpc error:', matchError.message);
1360→            } else if(Array.isArray(matches) && matches.length > 0){
1361→                const matchIds = matches.map((row) => row.id);
1362→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1363→
1364→                const {data: journals, error: errorJournals} = await supabase
1365→                    .from('journals')
1366→                    .select(selectColumns)
1367→                    .in('id', matchIds)
1368→                    .eq('privacy', 'public');
1369→
1370→                if(errorJournals){
1371→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1372→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1373→                }
1374→
1375→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1376→                const orderedSemantic = matchIds
1377→                    .map((id) => journalById.get(id))
1378→                    .filter(Boolean)
1379→                    .map((journal) => ({
1380→                        ...journal,
1381→                        similarity: similarityMap.get(journal.id) || null
1382→                    }));
1383→
1384→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1385→                const hasMore = withInteraction.length > parsedLimit;
1386→
1387→                return {
1388→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1389→                    hasMore: hasMore,
1390→                    mode: 'semantic'
1391→                };
1392→            }
1393→        }
1394→    } catch (error) {
1395→        console.error('semantic embedding/search fallback error:', error?.message || error);
1396→    }
1397→
1398→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1399→
1400→    const [titleResult, contentResult] = await Promise.all([
1401→        supabase
1402→            .from('journals')
1403→            .select(selectColumns)
1404→            .eq('privacy', 'public')
1405→            .ilike('title', `%${escapedQuery}%`)
1406→            .order('created_at', {ascending: false})
1407→            .order('id', {ascending: false})
1408→            .limit(parsedLimit + 1),
1409→        supabase
1410→            .from('journals')
1411→            .select(selectColumns)
1412→            .eq('privacy', 'public')
1413→            .ilike('content', `%${escapedQuery}%`)
1414→            .order('created_at', {ascending: false})
1415→            .order('id', {ascending: false})
1416→            .limit(parsedLimit + 1)
1417→    ]);
1418→
1419→    if(titleResult.error || contentResult.error){
1420→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1421→        throw {status: 500, error: 'supabase error while searching journals'};
1422→    }
1423→
1424→    const keywordMap = new Map();
1425→    (titleResult.data || []).forEach((journal) => {
1426→        keywordMap.set(journal.id, journal);
1427→    });
1428→    (contentResult.data || []).forEach((journal) => {
1429→        if(!keywordMap.has(journal.id)){
1430→            keywordMap.set(journal.id, journal);
1431→        }
1432→    });
1433→
1434→    const keywordJournals = [...keywordMap.values()];
1435→
1436→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1437→    const hasMore = withInteraction.length > parsedLimit;
1438→
1439→    return {
1440→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1441→        hasMore: hasMore,
1442→        mode: 'keyword'
1443→    };
1444→}
