 1→import express from "express";
 2→import cors from 'cors';
 3→import compression from "compression";
 4→import helmet from "helmet";
 5→import router from "./routes/routes.js";
 6→
 7→const app = express();
 8→const PORT = process.env.PORT || 3000;
 9→
10→const corsOptions = {
11→    origin: ['https://iskrib.com', 'https://iskrib-v3-client-side.onrender.com', 'http://localhost:5173'],
12→    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
13→    allowedHeaders: ['Content-Type', 'Authorization'],
14→    credentials: true,
15→    maxAge: 60 * 60 * 24
16→};
17→
18→app.use(cors(corsOptions));
19→app.use(compression({ threshold: 1024 }));
20→app.disable("x-powered-by");
21→app.use(
22→    helmet({
23→        contentSecurityPolicy: false,
24→        crossOriginEmbedderPolicy: false,
25→    })
26→);
27→
28→app.use((req, res, next) => {
29→    if (req.method === "GET" && !req.headers.authorization) {
30→        // no-cache: browser must revalidate with server before using cached response.
31→        // This prevents stale data after mutations (likes, comments, replies, etc.)
32→        // while still allowing conditional requests (304 Not Modified) for performance.
33→        // React Query handles client-side caching, so browser cache is unnecessary.
34→        res.set("Cache-Control", "no-cache");
35→    }
36→    next();
37→});
38→
39→app.use(express.json({ limit: "2mb" }));
40→app.use(express.urlencoded({extended: true, limit: "2mb", parameterLimit: 1000}));
41→
42→app.use('/api', router);
43→// Keep legacy root routes available while clients migrate to /api.
44→app.use(router)
45→
46→app.get('/', (req, res) => {
47→    res.send(`hello from backend port ${PORT}`)
48→})
49→
50→app.use((req, res) => {
51→    res.status(404).json({ error: "not found" });
52→});
53→
54→app.use((err, _req, res, _next) => {
55→    console.error("unhandled server error:", err?.message || err);
56→    res.status(500).json({ error: "internal server error" });
57→});
58→
59→app.listen(PORT, () =>{
