 1→import { useEffect } from "react";
 2→import { useLocation } from "react-router-dom";
 3→import {
 4→  DEFAULT_OG_IMAGE,
 5→  ORGANIZATION_SCHEMA,
 6→  buildAbsoluteUrl,
 7→  buildWebsiteSchema,
 8→  getSeoForPath,
 9→} from "./seoConfig.js";
10→
11→const ensureMeta = (id, attribute, key, content) => {
12→  let element = document.getElementById(id);
13→  if (!element) {
14→    element = document.createElement("meta");
15→    element.id = id;
16→    document.head.appendChild(element);
17→  }
18→
19→  element.setAttribute(attribute, key);
20→  element.setAttribute("content", content);
21→};
22→
23→const ensureLink = (id, rel, href, extra = {}) => {
24→  let element = document.getElementById(id);
25→  if (!element) {
26→    element = document.createElement("link");
27→    element.id = id;
28→    document.head.appendChild(element);
29→  }
30→
31→  element.setAttribute("rel", rel);
32→  element.setAttribute("href", href);
33→  Object.entries(extra).forEach(([name, value]) => {
34→    element.setAttribute(name, value);
35→  });
36→};
37→
38→const ensureJsonLd = (id, payload) => {
39→  let element = document.getElementById(id);
40→  if (!element) {
41→    element = document.createElement("script");
42→    element.id = id;
43→    element.type = "application/ld+json";
44→    document.head.appendChild(element);
45→  }
46→
47→  element.textContent = JSON.stringify(payload);
48→};
49→
50→const SeoManager = () => {
51→  const { pathname } = useLocation();
52→
53→  useEffect(() => {
54→    const seo = getSeoForPath(pathname);
55→    const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
56→    const ogTitle = seo.ogTitle || seo.title;
57→    const ogDescription = seo.ogDescription || seo.description;
58→    const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
59→
60→    document.title = seo.title;
61→
62→    ensureMeta("seo-description", "name", "description", seo.description);
63→    ensureMeta("seo-robots", "name", "robots", seo.robots || "index,follow");
64→
65→    ensureMeta("seo-og-type", "property", "og:type", "website");
66→    ensureMeta("seo-og-url", "property", "og:url", canonicalUrl);
67→    ensureMeta("seo-og-title", "property", "og:title", ogTitle);
68→    ensureMeta("seo-og-description", "property", "og:description", ogDescription);
69→    ensureMeta("seo-og-image", "property", "og:image", ogImage);
70→    ensureMeta("seo-og-site-name", "property", "og:site_name", "Iskryb");
71→
72→    ensureMeta("seo-twitter-card", "name", "twitter:card", "summary_large_image");
73→    ensureMeta("seo-twitter-title", "name", "twitter:title", ogTitle);
74→    ensureMeta("seo-twitter-description", "name", "twitter:description", ogDescription);
75→    ensureMeta("seo-twitter-image", "name", "twitter:image", ogImage);
76→
77→    ensureLink("seo-canonical", "canonical", canonicalUrl);
78→    ensureLink("seo-hreflang-en", "alternate", canonicalUrl, { hreflang: "en-US" });
79→    ensureLink("seo-hreflang-default", "alternate", canonicalUrl, {
80→      hreflang: "x-default",
81→    });
82→
83→    ensureJsonLd("seo-ld-website", buildWebsiteSchema(canonicalUrl));
84→    ensureJsonLd("seo-ld-organization", ORGANIZATION_SCHEMA);
85→  }, [pathname]);
86→
87→  return null;
88→};
89→
90→export default SeoManager;
