 60→    `<link id="seo-hreflang-default" rel="alternate" hreflang="x-default" href="${canonicalUrl}" />`
 61→  );
 62→
 63→  updated = replaceOrInsert(
 64→    updated,
 65→    /<meta[^>]*id=["']seo-og-type["'][^>]*>/i,
 66→    `<meta id="seo-og-type" property="og:type" content="website" />`
