183→    const {userId, loggedInUserId} = req.query;
184→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
185→    // console.log(req.query)
186→    try {
187→        const followersCountPromise = supabase
188→        .from('follows')
189→        .select('*', {count: 'exact', head: true})
190→        .eq('following_id', userId);
191→
192→        const followingCountPromise = supabase
193→        .from('follows')
194→        .select('*', {count: 'exact', head: true})
195→        .eq('follower_id', userId)
196→
197→        const isFollowingPromise = supabase
198→        .from('follows')
199→        .select('*', {count: 'exact', head: true})
200→        .eq('follower_id', loggedInUserId)
201→        .eq('following_id', userId)
202→
203→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
204→            followersCountPromise, followingCountPromise, isFollowingPromise,
205→        ])
206→
207→
208→        const {count: followersCount, error: errorFollowers } = followersCountResult;
209→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
210→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
211→
212→        if(errorFollowers || errorFollowings || errorIsfollowing){
213→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
214→            return res.status(500).json({error: 'failed to fetch data'})
215→        }
216→
217→        return res.status(200).json({
218→            followersCount: followersCount,
219→            followingsCount: followingsCount,
220→            isFollowing: isFollowingCount > 0
221→        })
222→
223→    } catch (error) {
224→        console.error('Error in Promise.all:', error);
225→        res.status(500).json({ error: 'An unexpected error occurred' });
226→    }
227→
228→})
